task.spawn(function()
    local game_loaders = {
        [1087859240] = "https://api.luarmor.net/files/v3/loaders/40db47a67f36abb41c12726416589845.lua",
        [1359573625] = {
            beta = "https://api.luarmor.net/files/v3/loaders/936841afb30c4e5a9f063bc16b25dd61.lua",
            stable = "https://api.luarmor.net/files/v3/loaders/157f311f0c03767c211de326c8a5f05f.lua"
        }
    }
    
    local game_id = game.GameId
    local loader_data = game_loaders[game_id]
    
    if not loader_data then
        return
    end
    
    local loader_url
    
    if type(loader_data) == "table" then
        loader_url = getgenv().beta_mode and loader_data.beta or loader_data.stable
    else
        loader_url = loader_data
    end
    
    loadstring(game:HttpGet(loader_url))()
end)
